mapper.select:
SELECT id, title, full_content, source_type, status, model, error_message, created_at, updated_at
FROM documents
WHERE id = #{id}

SELECT id, title, full_content, source_type, status, model, error_message, created_at, updated_at
FROM documents
WHERE status = #{status}
ORDER BY created_at ASC
LIMIT #{limit}

mapper.update:
UPDATE documents
SET status = #{status}, model = #{model}, error_message = NULL, updated_at = NOW()
WHERE id = #{id}

UPDATE documents
SET status = #{status}, error_message = #{errorMessage}, updated_at = NOW()
WHERE id = #{id}
